window.renderAvatarEl = function(avatarId, avatarColor, initial, size) {
    size = size || 40;
    const svg = avatarId && window.AVATARS[avatarId];
    if (svg) {
        const s = svg.replace('<svg ', '<svg style="display:block" width="' + size + '" height="' + size + '" ');
        return '<div style="width:' + size + 'px;height:' + size + 'px;border-radius:50%;overflow:hidden;flex-shrink:0;display:inline-block">' + s + '</div>';
    }
    const bg = avatarColor || '#1a56db';
    const fs = Math.round(size * 0.42);
    return '<div style="width:' + size + 'px;height:' + size + 'px;border-radius:50%;background:' + bg + ';display:inline-flex;align-items:center;justify-content:center;font-weight:700;color:#fff;font-size:' + fs + 'px;flex-shrink:0">' + (initial || '?') + '</div>';
};